import pytest
from source import levenshtein

def test_equal_first_char_does_not_add_cost():
    assert levenshtein('abc', 'abd') == 1, (
        "levenshtein('abc', 'abd') should be 1: only the last character differs, "
        "but the buggy code returns 2 by adding 1 for the matching 'a' prefix"
    )
    assert levenshtein('a', 'a') == 0, (
        "levenshtein('a', 'a') should be 0: identical strings have zero edit distance"
    )
    assert levenshtein('ab', 'ab') == 0, (
        "levenshtein('ab', 'ab') should be 0: identical strings have zero edit distance"
    )
